// packages/database/src/db/schema/message.ts
// Drizzle table: message (generated by scripts/split-schema.ts)

import { createId } from '@paralleldrive/cuid2'
import {
  type AnyPgColumn,
  bigint,
  boolean,
  index,
  integer,
  jsonb,
  pgTable,
  sendStatus,
  sql,
  text,
  timestamp,
  uniqueIndex,
} from './_shared'
import { EntityInstance } from './entity-instance'
import { Integration } from './integration'
import { Organization } from './organization'
import { Participant } from './participant'
import { StorageLocation } from './storage-location'
import { Thread } from './thread'
import { User } from './user'

/** Drizzle table for message */
export const Message = pgTable(
  'Message',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    externalId: text(),
    externalThreadId: text(),
    threadId: text()
      .notNull()
      .references((): AnyPgColumn => Thread.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    integrationId: text()
      .notNull()
      .references((): AnyPgColumn => Integration.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    isInbound: boolean().default(true).notNull(),
    isFirstInThread: boolean().default(true).notNull(),
    subject: text().notNull(),
    textHtml: text(),
    textPlain: text(),
    internetMessageId: text(),
    snippet: text(),
    metadata: jsonb(),
    createdById: text().references((): AnyPgColumn => User.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    fromId: text()
      .notNull()
      .references((): AnyPgColumn => Participant.id, { onUpdate: 'cascade', onDelete: 'restrict' }),
    replyToId: text().references((): AnyPgColumn => Participant.id, { onUpdate: 'cascade' }),
    isReply: boolean().default(false).notNull(),
    // You can use { mode: "bigint" } if numbers are exceeding js number limitations
    historyId: bigint({ mode: 'number' }),
    createdAt: timestamp({ precision: 3 }).notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    sentAt: timestamp({ precision: 3 }),
    receivedAt: timestamp({ precision: 3 }),
    signatureId: text().references((): AnyPgColumn => EntityInstance.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    htmlBodyStorageLocationId: text().references((): AnyPgColumn => StorageLocation.id, {
      onUpdate: 'cascade',
      onDelete: 'set null',
    }),
    hasAttachments: boolean().default(false).notNull(),
    attempts: integer().default(0).notNull(),
    lastAttemptAt: timestamp({ precision: 3 }),
    providerError: text(),
    sendStatus: sendStatus().default('SENT'),
    sendToken: text(),
  },
  (table) => [
    index('Message_createdById_idx').using('btree', table.createdById.asc().nullsLast()),
    index('Message_fromId_idx').using('btree', table.fromId.asc().nullsLast()),
    uniqueIndex('Message_integrationId_externalId_key').using(
      'btree',
      table.integrationId.asc().nullsLast(),
      table.externalId.asc().nullsLast()
    ),
    index('Message_integrationId_idx').using('btree', table.integrationId.asc().nullsLast()),
    index('Message_organizationId_idx').using('btree', table.organizationId.asc().nullsLast()),
    uniqueIndex('Message_organizationId_internetMessageId_key')
      .using(
        'btree',
        table.organizationId.asc().nullsLast(),
        table.internetMessageId.asc().nullsLast()
      )
      .where(sql`("internetMessageId" IS NOT NULL)`),
    index('Message_replyToId_idx').using('btree', table.replyToId.asc().nullsLast()),
    uniqueIndex('Message_sendToken_key')
      .using('btree', table.sendToken.asc().nullsLast())
      .where(sql`("sendToken" IS NOT NULL)`),
    index('Message_sentAt_idx').using('btree', table.sentAt.asc().nullsLast()),
    index('Message_threadId_createdById_idx').using(
      'btree',
      table.threadId.asc().nullsLast(),
      table.createdById.asc().nullsLast()
    ),
    index('Message_threadId_idx').using('btree', table.threadId.asc().nullsLast()),
    index('retry_queue_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.sendStatus.asc().nullsLast(),
      table.lastAttemptAt.asc().nullsLast()
    ),
    index('thread_messages_idx').using(
      'btree',
      table.threadId.asc().nullsLast(),
      table.sentAt.asc().nullsLast()
    ),
  ]
)

export type MessageEntity = typeof Message.$inferSelect
export type CreateMessageInput = typeof Message.$inferInsert
export type UpdateMessageInput = Partial<CreateMessageInput>
